        /// <summary>
        /// Metodo para darse de alta en el evento
        /// </summary>
        /// <param name="eventId"></param>
        /// <returns></returns>
        [HttpPost]
        [ValidateInput(false)]
        public JsonResult GoEvent(int eventId)
        {

            Validations.EventRegistration vEventRegistration = new Validations.EventRegistration();
            Entities.Employees eEmployee = null;
            if (Session["User"] != null)
            {
                eEmployee = (Entities.Employees)Session["User"];
            }

            Entities.ViewModels.EventRegistrationView events = Data.EventRegistration.GetAllEventRegistrationByUser(eEmployee.Idhrms).SingleOrDefault(x => x.EventId == eventId);

            Entities.EventRegistration eventRegistration = new Entities.EventRegistration();
            eventRegistration.EventId = eventId;
            eventRegistration.PersonId = eEmployee.Idhrms;
            eventRegistration.Registration = 1;

            bool totalAvailableQuotas = vEventRegistration.ValidateTotalAvailableQuotas(eventId);
            if (totalAvailableQuotas == false)
            {
                return Json(new { status = "Error", message = "No hay cupos disponibles para el evento" });
            }

            bool eventClosed = vEventRegistration.ValidateEventClosed(eventId);
            if (eventClosed == false)
            {
                return Json(new { status = "Error", message = "El evento ya esta cerrado" });
            }
            bool userRegistered = vEventRegistration.ValidateEventUserRegistered(eventId);
            if (userRegistered == false)
            {
                return Json(new { status = "Error", message = "Usted ya se ha inscrito en este evento" });
            }
           
            
            if (events.Registration == 0)
            {

                string result = Data.EventRegistration.InsertRegistration(eventRegistration);
                if (result == "Exito al insertar el registro")
                {
                    return Json(new { status = "Exito", message = "Su inscripcion en el evento ha sido actualizada" });
                }

            }
            if (events.Registration == 2)
            {
               
                string result = Data.EventRegistration.UpdateRegistration(eventRegistration);
                if (result == "Exito al actualizar el registro")
                {
                    return Json(new { status = "Exito", message = "Su inscripcion en el evento ha sido actualizada" });
                }

            }



            return Json(new { status = "Error", message = "Error en la transaccion" });
        }

        /// <summary>
        /// Metodo para darse de baja del evento
        /// </summary>
        /// <param name="eventId"></param>
        /// <returns></returns>
        [HttpPost]
        [ValidateInput(false)]
        public JsonResult DontGoEvent(int eventId)
        {

            Entities.Employees eEmployee = null;
            if (Session["User"] != null)
            {
                eEmployee = (Entities.Employees)Session["User"];
            }

            var eventByUser = Data.EventRegistration.GetAllEventRegistrationByUser(eEmployee.Idhrms).Where(x=> x.EventId == eventId).FirstOrDefault();
            if (eventByUser != null)
            {
                if (eventByUser.Registration == 0 || eventByUser.Registration == 2)
                {
                    return Json(new { status = "Error", message = "Solo se puede dar de baja si se ha inscrito al evento" });
                }
               
            }

            Entities.EventRegistration eventRegistration = new Entities.EventRegistration();
            eventRegistration.EventId = eventId;
            eventRegistration.PersonId = eEmployee.Idhrms;
            eventRegistration.Registration = 2;

            string result = Data.EventRegistration.UpdateRegistration(eventRegistration);
            if (result == "Exito al actualizar el registro")
            {
                return Json(new { status = "Exito", message = "Su baja del evento ha sido actualizada" });
            }
            return Json(new { status = "Error", message = "Error en la transaccion" });
        }


