        [HttpPost]
        [ValidateAntiForgeryToken]
        public JsonResult GoEventx(int eventId)
        {
            try
            {
                Validations.EventRegistration vEventRegistration = new Validations.EventRegistration();
                Entities.Employees eEmployee = null;

                if (Session["User"] != null)
                {
                    eEmployee = (Entities.Employees)Session["User"];
                }

                Entities.ViewModels.EventRegistrationView registro = Data.EventRegistration.GetAllEventRegistrationByUser(eEmployee.Idhrms)
                    .SingleOrDefault(x => x.EventId == eventId);

                Entities.EventRegistration eventRegistration = new Entities.EventRegistration
                {
                    EventId = eventId,
                    PersonId = eEmployee.Idhrms,
                    Registration = 1
                };

                // Validaciones
                if (!vEventRegistration.ValidateTotalAvailableQuotas(eventId))
                {
                    return Json(new { status = "Error", message = "No hay cupos disponibles para el evento" });
                }

                if (!vEventRegistration.ValidateEventClosed(eventId))
                {
                    return Json(new { status = "Error", message = "El evento ya está cerrado" });
                }

                if (!vEventRegistration.ValidateEventUserRegistered(eventId))
                {
                    return Json(new { status = "Error", message = "Usted ya se ha inscrito en este evento" });
                }

                string result;

                if (registro == null || registro.Registration == 0)
                {
                    result = Data.EventRegistration.InsertRegistration(eventRegistration);
                }
                else if (registro.Registration == 2)
                {
                    result = Data.EventRegistration.UpdateRegistration(eventRegistration);
                }
                else
                {
                    return Json(new { status = "Error", message = "Estado de inscripción inválido." });
                }

                if (result == "Exito al insertar el registro" || result == "Exito al actualizar el registro")
                {
                    return Json(new { status = "Exito", message = "Su inscripción en el evento ha sido actualizada" });
                }

                return Json(new { status = "Error", message = "Error en la transacción" });
            }
            catch (Exception ex)
            {
                // Manejo de excepciones
                return Json(new { status = "Error", message = ex.Message });
            }
        }

        // Acción para darse de baja del evento
        [HttpPost]
        [ValidateAntiForgeryToken]
        public JsonResult DontGoEventx(int eventId)
        {
            try
            {
                Entities.Employees eEmployee = null;
                if (Session["User"] != null)
                {
                    eEmployee = (Entities.Employees)Session["User"];
                }

                var registro = Data.EventRegistration.GetAllEventRegistrationByUser(eEmployee.Idhrms)
                    .FirstOrDefault(x => x.EventId == eventId);

                if (registro != null && (registro.Registration == 0 || registro.Registration == 2))
                {
                    return Json(new { status = "Error", message = "Solo se puede dar de baja si se ha inscrito al evento" });
                }

                Entities.EventRegistration eventRegistration = new Entities.EventRegistration
                {
                    EventId = eventId,
                    PersonId = eEmployee.Idhrms,
                    Registration = 2
                };

                string result = Data.EventRegistration.UpdateRegistration(eventRegistration);

                if (result == "Exito al actualizar el registro")
                {
                    return Json(new { status = "Exito", message = "Su baja del evento ha sido actualizada" });
                }

                return Json(new { status = "Error", message = "Error en la transacción" });
            }
            catch (Exception ex)
            {
                // Manejo de excepciones
                return Json(new { status = "Error", message = ex.Message });
            }
        }

        public JsonResult GetAllempleadoevento()
        {
            List<empleadoevento> lstGratefulness = new List<empleadoevento>();

            if (Session["empleadoevento"] != null)
            {
                lstGratefulness = (List<empleadoevento>)Session["empleadoevento"];
            }
            else
            {
                // Supongo que este método devuelve un string JSON enorme
                var lstEmp = Employee.GeteventoempleadoAsyncx();

                if (lstEmp != null)
                {
                    // 1. Usamos el serializador con límite aumentado (como te enseñé antes)
                    var serializer = new System.Web.Script.Serialization.JavaScriptSerializer();
                    serializer.MaxJsonLength = Int32.MaxValue;

                    var deserializedObject = serializer.Deserialize<List<empleadoevento>>(lstEmp);

                    // 2. CORRECCIÓN LÓGICA: Asignamos a la variable que vamos a retornar
                    lstGratefulness = deserializedObject;

                    Session["empleadoevento"] = lstGratefulness;
                }
            }

            // 3. CORRECCIÓN DE SALIDA: Aumentamos el límite para enviar el JSON al navegador
            var jsonResult = Json(new { data = lstGratefulness }, JsonRequestBehavior.AllowGet);
            jsonResult.MaxJsonLength = Int32.MaxValue; // IMPORTANTE: Permitir enviar los 11k registros

            return jsonResult;
        }
