        public JsonResult RegistrarAsistencia(registromaestro registromaestro )
        {
        
            List<empleadoevento> TEMP = new List<empleadoevento>();
            if (Session["empleadoevento"] != null)
            {
                TEMP = (List<empleadoevento>)Session["empleadoevento"];
            
            }

            // Filtra por el código proporcionado
            var empleado = TEMP.FirstOrDefault(e => e.CODIGO == registromaestro.employeeId);
            if (empleado.FECHAFIN!= "No tiene")
            {
                DateTime fechaFin;
                // Intentamos convertir FECHAFIN a DateTime
                bool isDateValid = DateTime.TryParse(empleado.FECHAFIN, out fechaFin);

                if (isDateValid)
                {
                    // Si la fecha es válida, verificamos si ya ha pasado
                    if (fechaFin < DateTime.Now)
                    {
                        return Json(new { success = false, message = "El Empleado está de baja, la fecha ya ha pasado" });
                    }
                    else
                    {
                        
                    }
                }
                 
               

            }
            bool registroExitoso = RegistrarAsistenciaAsync(registromaestro.employeeId, registromaestro.totalPersons, registromaestro.totalPersons2);

            if (registroExitoso)
            {
                return Json(new { success = true, message = "Registro exitoso." });
            }
            else
            {
                return Json(new { success = false, message = "El registro ya existe." });
            }
        }

        public   bool  RegistrarAsistenciaAsync(string employeeId, int totalPersons, int totalPersons2)
        {
         int EVENTID= (int)Session["eventocodigo"] ;

            using (IDbConnection db = new SqlConnection(connectionString))
            {
                // Comprobar si el registro existe para el empleado y el evento
                var queryExistencia = @"SELECT COUNT(1) 
                                    FROM dbo.tblAsistencia 
                                    WHERE Empleado = @Empleado AND Evento = @Evento";
               
            
                 var existe =   db.ExecuteScalar<int>(queryExistencia, new { Empleado = employeeId, Evento = EVENTID });

                if (existe > 0)
                {
                    // Registro ya existe, no se realiza inserción
                    return false;
                }
                List<empleadoevento> TEMP = new List<empleadoevento>();
                if (Session["empleadoevento"] != null)
                {
                    TEMP = (List<empleadoevento>)Session["empleadoevento"];
                }

                // Filtra por el código proporcionado
                var empleado = TEMP.FirstOrDefault(e => e.CODIGO == employeeId);

                // Insertar el nuevo registro
                var queryInsert = @"
                INSERT INTO dbo.tblAsistencia 
                (Empleado, Familiar, Evento, Gerencia, Dpto, Tiquet1, Acompañantes, Tiquet3, Tiquet4, 
                 Tiquet5, Tiquet6, adulto, niño, Usuario)
                VALUES 
                (@Empleado, @Familiar, @Evento, @Gerencia, @Dpto, @Tiquet1, @Acompañantes, @Tiquet3, 
                 @Tiquet4, @Tiquet5, @Tiquet6, @adulto, @niño, @Usuario)";

                var parametros = new
                {
                    Empleado = employeeId,
                    Familiar = 1,
                    Evento = EVENTID,
                    Gerencia = empleado.GERENCIA,
                    Dpto = empleado.DEPARTAMENTO,
                    Tiquet1 = totalPersons+ totalPersons2,
                    Acompañantes = 0,
                    Tiquet3 = 0,
                    Tiquet4 = 0,
                    Tiquet5 = 0,
                    Tiquet6 = 0,
                    adulto = totalPersons,
                    niño = totalPersons2,
                    Usuario = 0028
                };

                  db.Execute (queryInsert, parametros);
                return true;
            }
        }

        [HttpGet]
public JsonResult ObtenerAsistenciaConNombre()
        {
            using (var connection = new SqlConnection(connectionString))
            {
                int EVENTID = (int)Session["eventocodigo"];
                // Consulta de Dapper para obtener todos los registros en tblAsistencia
                var asistencia = connection.Query<AsistenciaModel>(@"
            SELECT Empleado, Fecha, Gerencia, Dpto, adulto, niño 
            FROM tblAsistencia 
            WHERE Evento = @EventoId", new { EventoId = EVENTID }).ToList();


                // Obtener la lista temporal de empleadoevento desde la sesión
                List<empleadoevento> TEMP = new List<empleadoevento>();
                if (Session["empleadoevento"] != null)
                {
                    TEMP = (List<empleadoevento>)Session["empleadoevento"];
                }

                // Combina los datos agregando el nombre del empleado desde TEMP
                var asistenciaConNombre = asistencia.Select(a => new
                {
                    Empleado = a.Empleado,
                    Nombre = TEMP.FirstOrDefault(e => e.CODIGO == a.Empleado)?.NOMBRE ?? "Desconocido",
                    Fecha = a.Fecha,
                    Gerencia = a.Gerencia,
                    Dpto = a.Dpto,
                    Adulto = a.Adulto,
                    Niño = a.Niño
                }).ToList();

                return Json(new { data = asistenciaConNombre }, JsonRequestBehavior.AllowGet);
            }
        }
