        {
            // Cache por sesión (opcional)
            var cacheKey = "familiaevento_api_" + (codigo ?? "").Trim();
            var cache = Session[cacheKey] as List<Familiaevento>;
            if (cache != null)
                return Json(new { data = cache }, JsonRequestBehavior.AllowGet);

            var resultado = new List<Familiaevento>();

            // --- Configuración de tu API ---
            string baseUrl = "https://fa-exjp-saasfaprod1.fa.ocs.oraclecloud.com/hcmRestApi/resources/11.13.18.05/hcmContacts";
            string q = "?q=contactRelationships.RelatedPersonNumber='" + Uri.EscapeDataString((codigo ?? "").Trim()) +
                       "'&expand=names,contactRelationships&onlyData=true";
