            try
            {
                // TLS 1.2
                ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;

                // Solicitud HTTP (MISMO PATRÓN)
                HttpWebRequest request = (HttpWebRequest)WebRequest.Create(url);
                string authHeader = Convert.ToBase64String(Encoding.GetEncoding("ISO-8859-1").GetBytes(usuario + ":" + contraseña));
                request.Headers.Add("Authorization", "Basic " + authHeader);
                request.Headers.Add("REST-Framework-Version", "2");
                request.AutomaticDecompression = DecompressionMethods.GZip | DecompressionMethods.Deflate;
                request.Method = "GET";
                request.Accept = "application/json";

                using (HttpWebResponse response = (HttpWebResponse)request.GetResponse())
                using (Stream responseStream = response.GetResponseStream())
                {
                    if (response.StatusCode == HttpStatusCode.OK && responseStream != null)
                    {
                        // Leer JSON
                        using (var reader = new StreamReader(responseStream, Encoding.UTF8))
                        {
                            string json = reader.ReadToEnd();

                            // Deserializar
                            var parsed = Newtonsoft.Json.JsonConvert.DeserializeObject<HcmContactsResponse>(json);
                            if (parsed != null && parsed.items != null)
                            {
                                DateTime hoy = DateTime.UtcNow.Date;

                                foreach (var it in parsed.items)
