                                        nombre = it.names[0].FullName.Trim();

                                    // Tipo relación (prioriza PrimaryContactFlag=true)
                                    string tipoRela = "";
                                    if (it.contactRelationships != null && it.contactRelationships.Count > 0)
                                    {
                                        HcmRel sel = null;
                                        for (int i = 0; i < it.contactRelationships.Count; i++)
                                        {
                                            var r = it.contactRelationships[i];
                                            if (r.PrimaryContactFlag.HasValue && r.PrimaryContactFlag.Value) { sel = r; break; }
                                        }

                                        if (sel == null) sel = it.contactRelationships[0];

                                        if (sel != null && !string.IsNullOrWhiteSpace(sel.ContactType))
                                        {
                                           tipoRela = MapTipoContacto(sel.ContactType); // ← mapea a la etiqueta en ESPAÑOL (mayúsculas)
                                        }
                                    }

                                    // Edad (años completos)
                                    decimal edad = 0m;
                                    DateTime dob;
                                    if (!string.IsNullOrWhiteSpace(it.DateOfBirth) && DateTime.TryParse(it.DateOfBirth, out dob))
                                    {
                                        int years = hoy.Year - dob.Year;
                                        if (new DateTime(hoy.Year, dob.Month, dob.Day) > hoy) years--;
                                        if (years < 0) years = 0;
                                        edad = years;
                                    }
                                    if (tipoRela=="CONTACTO")
                                    {

                                    }
                                    else if (tipoRela!="" && tipoRela!=null)
                                    { 
                                    resultado.Add(new Familiaevento
                                    {
                                        CODIGO = (codigo ?? "").Trim(),
                                        NOMBRE_HIJO = nombre,
                                        TIPO_RELA = tipoRela,
                                        EDAD = edad
                                    });
                                    }
                                }
                            }
                        }
                    }
                }

                // Cachear en sesión
                Session[cacheKey] = resultado;
                return Json(new { data = resultado }, JsonRequestBehavior.AllowGet);
            }
            catch (  Exception wex)
            {
                // Comentario clave: si la API devuelve 4xx/5xx, intenta leer mensaje para depurar (no romper UI)
                return null;
            }
            
        }
        private static bool EsTipoM(string code)
        {
            return !string.IsNullOrWhiteSpace(code)
                && code.Trim().Equals("M", StringComparison.OrdinalIgnoreCase);
        }

        private static HcmRel ElegirRelacionNoM(List<HcmRel> relaciones)
        {
            if (relaciones == null || relaciones.Count == 0) return null;

            // 1) Primaria distinta de "M"
            for (int i = 0; i < relaciones.Count; i++)
            {
                var r = relaciones[i];
                if (r.PrimaryContactFlag.HasValue && r.PrimaryContactFlag.Value && !EsTipoM(r.ContactType))
                    return r;
            }
            // 2) Primera distinta de "M"
            for (int i = 0; i < relaciones.Count; i++)
            {
                var r = relaciones[i];
                if (!EsTipoM(r.ContactType)) return r;
            }
            // 3) Todas son "M" → null (se omite el item)
            return null;
        }
        private static string MapTipoContacto(string code)
        {
            if (string.IsNullOrWhiteSpace(code)) return "";
            code = code.Trim().ToUpperInvariant();
            // Diccionario mínimo (code → etiqueta)
            // NOTA: Se guarda SIEMPRE EN MAYÚSCULAS como pediste.
            var map = new Dictionary<string, string>
    {
        { "S", "CÓNYUGE" },
        { "C", "HIJO/HIJA" },
        { "IN_MR", "MADRE" },
        { "IN_FR", "PADRE" },
        { "ORA_HRX_STB_UNION", "PAREJA CON DECLARACIÓN DE UNIÓN ESTABLE" },
        { "BROTHER", "HERMANO" },
        { "SISTER", "HERMANA" },
        { "NEPHEW", "SOBRINO" },
        { "M", "CONTACTO" },
        { "F", "AMIGO/AMIGA" },
        { "T", "HIJASTRO/HIJASTRA" },
        { "ORA_HRX_AUNT", "TÍA" },
        { "ORA_HRX_OR", "OTRO FAMILIAR" },
        { "ORA_HRX_UNCLE", "TÍO" },
        { "ORA_HRX_SP", "PADRASTRO/MADRASTRA" },
        { "NIECE", "SOBRINA" },
        { "ORA_HRX_GRANDDAUGHTER", "NIETA" },
        { "GC", "NIETO/NIETA" },
        { "CH_GRANDFATHER", "ABUELO" }
    };
            string etiqueta;
            if (map.TryGetValue(code, out etiqueta)) return etiqueta;
            return code; // fallback: guarda el código tal cual en mayúsculas
        }
        public JsonResult GetFamiliaresPorCodigo(string codigo)
        {
            List<Familiaevento> lstGratefulness = new List<Familiaevento>();

            if (Session["familiaevento"] != null)
            {
                lstGratefulness = (List<Familiaevento>)Session["familiaevento"];
            }
            else
            {
                var lstEmp = Employee.GeteventofamiliaAsyncx();
                if (lstEmp != null)
                {
                    var deserializedObject = new JavaScriptSerializer().Deserialize<List<Familiaevento>>(lstEmp);
                    lstGratefulness = deserializedObject.ToList();
                    Session["familiaevento"] = lstGratefulness;
                }
            }

            // Filtra los familiares usando el código proporcionado
            var familiaresFiltrados = lstGratefulness.Where(f => f.CODIGO == codigo).ToList();

            return Json(new { data = familiaresFiltrados }, JsonRequestBehavior.AllowGet);
        }

