        [HttpGet]
        public JsonResult ObtenerResumenInventario()
        {
            try
            {
                using (var connection = new SqlConnection(connectionString))
                {
                    string sql = @"
                        SELECT Categoria, GeneroHijo, 
                               SUM(CASE WHEN Entregado = 1 THEN 1 ELSE 0 END) AS Entregados,
                               SUM(CASE WHEN Entregado = 0 THEN 1 ELSE 0 END) AS Pendientes,
                               COUNT(1) AS Total
                        FROM dbo.tblDespachoJuguetesDiaNino
                        GROUP BY Categoria, GeneroHijo";
                    
                    var resumen = connection.Query<ResumenInventarioModel>(sql).ToList();
                    return Json(new { success = true, data = resumen }, JsonRequestBehavior.AllowGet);
                }
            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message }, JsonRequestBehavior.AllowGet);
            }
        }

