        [HttpGet]
        public ActionResult DescargarReporteDespachoPDF()
        {
            try
            {
                List<DespachoHijoModel> list;
                using (var connection = new SqlConnection(connectionString))
                {
                    string sql = @"
                        SELECT h.Id, h.CarnetColaborador, h.NombreColaborador, h.NombreHijo, h.EdadHijo, h.GeneroHijo, 
                               h.Categoria, h.GerenciaColaborador, h.UbicacionColaborador, h.Entregado, h.FechaEntrega, h.UsuarioDespacho,
                               COALESCE(c.NombreJuguete, 'Juguete por definir') AS RegaloSugerido
                        FROM dbo.tblDespachoJuguetesDiaNino h
                        LEFT JOIN dbo.tblCatalogoJuguetesDiaNino c 
                          ON h.Categoria = c.Categoria 
                         AND (c.Genero = h.GeneroHijo OR (c.Genero = 'TODOS' AND NOT EXISTS (
                             SELECT 1 FROM dbo.tblCatalogoJuguetesDiaNino sub 
                             WHERE sub.Categoria = h.Categoria AND sub.Genero = h.GeneroHijo
                         )))
                        ORDER BY h.NombreColaborador, h.NombreHijo";
                    list = connection.Query<DespachoHijoModel>(sql).ToList();
                }

                int totalCenso = list.Count;
                int totalEntregados = list.Count(x => x.Entregado);
                int totalPendientes = totalCenso - totalEntregados;

                using (var ms = new MemoryStream())
                {
                    iTextSharp.text.Document document = new iTextSharp.text.Document(iTextSharp.text.PageSize.LETTER.Rotate(), 25, 25, 25, 25);
                    iTextSharp.text.pdf.PdfWriter writer = iTextSharp.text.pdf.PdfWriter.GetInstance(document, ms);
                    document.Open();

                    var fontTitle = iTextSharp.text.FontFactory.GetFont(iTextSharp.text.FontFactory.HELVETICA_BOLD, 16, new iTextSharp.text.BaseColor(218, 18, 26));
                    var fontSubTitle = iTextSharp.text.FontFactory.GetFont(iTextSharp.text.FontFactory.HELVETICA_BOLD, 11, iTextSharp.text.BaseColor.DARK_GRAY);
                    var fontHeader = iTextSharp.text.FontFactory.GetFont(iTextSharp.text.FontFactory.HELVETICA_BOLD, 8, iTextSharp.text.BaseColor.WHITE);
                    var fontCell = iTextSharp.text.FontFactory.GetFont(iTextSharp.text.FontFactory.HELVETICA, 7, iTextSharp.text.BaseColor.BLACK);
                    var fontBoldCell = iTextSharp.text.FontFactory.GetFont(iTextSharp.text.FontFactory.HELVETICA_BOLD, 7, iTextSharp.text.BaseColor.BLACK);

                    iTextSharp.text.Paragraph title = new iTextSharp.text.Paragraph("REPORTE GENERAL DE ENTREGA DE JUGUETES - DIA DEL NIÑO\n", fontTitle);
                    title.Alignment = iTextSharp.text.Element.ALIGN_CENTER;
                    document.Add(title);

                    iTextSharp.text.Paragraph subtitle = new iTextSharp.text.Paragraph("Fecha de Emisión: " + DateTime.Now.ToString("dd/MM/yyyy HH:mm") + "\n\n", fontSubTitle);
                    subtitle.Alignment = iTextSharp.text.Element.ALIGN_CENTER;
                    document.Add(subtitle);

                    iTextSharp.text.pdf.PdfPTable tableSummary = new iTextSharp.text.pdf.PdfPTable(3);
                    tableSummary.WidthPercentage = 40;
                    tableSummary.HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER;
                    tableSummary.SpacingAfter = 15;

                    iTextSharp.text.pdf.PdfPCell cellTotal = new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase("Censados: " + totalCenso, fontSubTitle));
                    cellTotal.Border = iTextSharp.text.Rectangle.BOX;
                    cellTotal.Padding = 6;
                    cellTotal.HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER;
                    tableSummary.AddCell(cellTotal);

                    iTextSharp.text.pdf.PdfPCell cellEntregados = new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase("Entregados: " + totalEntregados, fontSubTitle));
                    cellEntregados.Border = iTextSharp.text.Rectangle.BOX;
                    cellEntregados.Padding = 6;
                    cellEntregados.HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER;
                    cellEntregados.BackgroundColor = new iTextSharp.text.BaseColor(236, 253, 245);
                    tableSummary.AddCell(cellEntregados);

                    iTextSharp.text.pdf.PdfPCell cellPendientes = new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase("Pendientes: " + totalPendientes, fontSubTitle));
                    cellPendientes.Border = iTextSharp.text.Rectangle.BOX;
                    cellPendientes.Padding = 6;
                    cellPendientes.HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER;
                    cellPendientes.BackgroundColor = new iTextSharp.text.BaseColor(249, 250, 251);
                    tableSummary.AddCell(cellPendientes);

                    document.Add(tableSummary);

                    iTextSharp.text.pdf.PdfPTable table = new iTextSharp.text.pdf.PdfPTable(9);
                    table.WidthPercentage = 100;
                    table.SetWidths(new float[] { 60f, 150f, 150f, 35f, 75f, 180f, 65f, 75f, 85f });

                    string[] headers = { "Carnet", "Colaborador", "Hijo", "Gen", "Rango", "Juguete Asignado/Entregado", "Estado", "Despachó", "Fecha Entrega" };
                    foreach (var h in headers)
                    {
                        iTextSharp.text.pdf.PdfPCell cell = new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(h, fontHeader));
                        cell.BackgroundColor = new iTextSharp.text.BaseColor(30, 30, 30);
                        cell.HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER;
                        cell.VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE;
                        cell.Padding = 5;
                        table.AddCell(cell);
                    }

                    foreach (var item in list)
                    {
                        table.AddCell(new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(item.CarnetColaborador, fontCell)) { Padding = 4, VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE });
                        table.AddCell(new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(item.NombreColaborador, fontCell)) { Padding = 4, VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE });
                        table.AddCell(new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(item.NombreHijo, fontCell)) { Padding = 4, VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE });
                        table.AddCell(new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(item.GeneroHijo, fontCell)) { Padding = 4, HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER, VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE });
                        table.AddCell(new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(item.Categoria, fontCell)) { Padding = 4, HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER, VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE });
                        table.AddCell(new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(item.RegaloSugerido, fontCell)) { Padding = 4, VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE });

                        string estadoText = item.Entregado ? "ENTREGADO" : "PENDIENTE";
                        var fontColor = item.Entregado ? new iTextSharp.text.BaseColor(5, 150, 105) : new iTextSharp.text.BaseColor(107, 114, 128);
                        var cellFont = iTextSharp.text.FontFactory.GetFont(iTextSharp.text.FontFactory.HELVETICA_BOLD, 7, fontColor);
                        iTextSharp.text.pdf.PdfPCell cellEstado = new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(estadoText, cellFont));
                        cellEstado.Padding = 4;
                        cellEstado.HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER;
                        cellEstado.VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE;
                        table.AddCell(cellEstado);

                        table.AddCell(new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(item.UsuarioDespacho ?? "-", fontCell)) { Padding = 4, HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER, VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE });

                        string fechaText = item.FechaEntrega.HasValue ? item.FechaEntrega.Value.ToString("dd/MM/yyyy HH:mm") : "-";
                        table.AddCell(new iTextSharp.text.pdf.PdfPCell(new iTextSharp.text.Phrase(fechaText, fontCell)) { Padding = 4, HorizontalAlignment = iTextSharp.text.Element.ALIGN_CENTER, VerticalAlignment = iTextSharp.text.Element.ALIGN_MIDDLE });
                    }

                    document.Add(table);
                    document.Close();

                    byte[] pdfBytes = ms.ToArray();
                    string fileName = "Reporte_Despacho_Juguetes_" + DateTime.Now.ToString("yyyyMMdd_HHmm") + ".pdf";
                    return File(pdfBytes, "application/pdf", fileName);
                }
            }
            catch (Exception ex)
            {
                return Content("Error al generar el reporte PDF: " + ex.Message, "text/plain");
            }
        }

        [HttpPost]
        public JsonResult GuardarJugueteCatalogo(int id, string categoria, string genero, string nombreJuguete, int stockInicial, int stockActual, string fotoBase64)
        {
            try
            {
                categoria = (categoria ?? "").Trim();
                genero = (genero ?? "").Trim().ToUpper();
                nombreJuguete = (nombreJuguete ?? "").Trim();

                if (string.IsNullOrEmpty(categoria) || string.IsNullOrEmpty(genero) || string.IsNullOrEmpty(nombreJuguete))
                {
                    return Json(new { success = false, message = "Todos los campos obligatorios deben completarse." });
                }

                using (var connection = new SqlConnection(connectionString))
                {
                    // Validar si ya existe esa combinación de Categoría y Género para otro juguete
                    string sqlCheck = "SELECT COUNT(1) FROM dbo.tblCatalogoJuguetesDiaNino WHERE Categoria = @Categoria AND Genero = @Genero AND Id <> @Id";
                    int count = connection.ExecuteScalar<int>(sqlCheck, new { Categoria = categoria, Genero = genero, Id = id });
                    if (count > 0)
                    {
                        return Json(new { success = false, message = "Ya existe un juguete configurado para la categoría '" + categoria + "' y el género '" + genero + "'." });
                    }

                    if (id == 0)
                    {
                        string sqlInsert = @"
                            INSERT INTO dbo.tblCatalogoJuguetesDiaNino (Categoria, Genero, NombreJuguete, StockInicial, StockActual, FotoBase64)
                            VALUES (@Categoria, @Genero, @NombreJuguete, @StockInicial, @StockActual, @FotoBase64)";
                        connection.Execute(sqlInsert, new { Categoria = categoria, Genero = genero, NombreJuguete = nombreJuguete, StockInicial = stockInicial, StockActual = stockActual, FotoBase64 = fotoBase64 });
                        return Json(new { success = true, message = "Juguete agregado exitosamente al catálogo." });
                    }
                    else
                    {
                        string sqlUpdate = @"
                            UPDATE dbo.tblCatalogoJuguetesDiaNino
                            SET Categoria = @Categoria,
                                Genero = @Genero,
                                NombreJuguete = @NombreJuguete,
                                StockInicial = @StockInicial,
                                StockActual = @StockActual,
                                FotoBase64 = @FotoBase64
                            WHERE Id = @Id";
                        connection.Execute(sqlUpdate, new { Categoria = categoria, Genero = genero, NombreJuguete = nombreJuguete, StockInicial = stockInicial, StockActual = stockActual, FotoBase64 = fotoBase64, Id = id });
                        return Json(new { success = true, message = "Juguete actualizado exitosamente." });
                    }
                }
            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message });
            }
        }

